const payload = $input.first().json;

// VAPI payload structure — handle both possible formats
const message = payload.message || payload;
const toolCalls = message.toolCallList || message.toolCalls || [];
const toolCall = toolCalls[0] || {};
const args = toolCall.function?.arguments || {};
const userQuery = (typeof args === 'string' ? JSON.parse(args) : args).question || '';
const toolCallId = toolCall.id || '';

// Validate
if (!userQuery || userQuery.trim().length < 3) {
  return [{
    json: {
      toolCallId,
      intent: 'clarify',
      clarification_question: "I didn't quite catch that. Could you please repeat your question?",
      response: "I didn't quite catch that. Could you please repeat your question?",
      skipProcessing: true
    }
  }];
}

return [{
  json: {
    toolCallId,
    userQuery: userQuery.trim(),
    skipProcessing: false
  }
}];

const input = $input.first().json;
const upstream = $('Extract & Validate Input').first().json;

let classification;
try {
  const text = input.content?.[0]?.text || input.content || '{}';
  classification = typeof text === 'string' ? JSON.parse(text) : text;
} catch(e) {
  classification = { intent: 'escalate', category: 'general', escalation_reason: 'Failed to classify intent' };
}

return [{
  json: {
    ...upstream,
    intent: classification.intent || 'escalate',
    category: classification.category || 'general',
    clarification_question: classification.clarification_question || '',
    escalation_reason: classification.escalation_reason || ''
  }
}];

const upstream = $('Extract & Validate Input').first().json;
return [{
  json: {
    toolCallId: upstream.toolCallId,
    response: "I don't have specific information about that in my knowledge base. Let me connect you with our support team who can help you further. You can also email support@relaypay.co."
  }
}];

const input = $input.first().json;
const upstream = $('Extract & Validate Input').first().json;
const answerText = input.content?.[0]?.text || input.content || 'I was unable to generate an answer. Please contact support@relaypay.co.';
return [{
  json: {
    toolCallId: upstream.toolCallId,
    response: answerText
  }
}];

const data = $input.first().json;
const clarificationQ = data.clarification_question || 'Could you give me a bit more detail about your question?';
return [{
  json: {
    response: clarificationQ,
    toolCallId: data.toolCallId
  }
}];

const data = $input.first().json;
const reason = data.escalation_reason || 'Account-specific inquiry';
return [{
  json: {
    response: "That's something our support team can help you with directly. You can reach them at support@relaypay.co, or through the live chat on our website during business hours. They'll be able to look into your account and sort this out.",
    toolCallId: data.toolCallId,
    escalated: true,
    escalation_reason: reason,
    original_query: data.userQuery
  }
}];

const data = $input.first().json;
const logEntry = {
  timestamp: new Date().toISOString(),
  userQuery: data.userQuery || data.original_query || '',
  intent: data.intent || 'escalate',
  category: data.category || 'general',
  response: (data.response || '').substring(0, 500),
  escalated: data.escalated || false,
  escalation_reason: data.escalation_reason || ''
};
console.log('RELAYPAY_LOG:', JSON.stringify(logEntry));
return [{ json: logEntry }];

const data = $input.first().json;

return [{
  json: {
    results: [
      {
        toolCallId: data.toolCallId,
        result: data.response
      }
    ]
  }
}];
